import os
import sys
import time
from google import genai

def test_api():
    api_key = os.environ.get("GOOGLE_API_KEY")
    if not api_key:
        print("❌ Error: GOOGLE_API_KEY not found in environment.")
        return

    print(f"🔍 Testing API Key: {api_key[:5]}...{api_key[-5:]}")

    try:
        client = genai.Client(api_key=api_key)

        # 1. Test Embedding
        embed_models = ["models/gemini-embedding-2-preview", "models/gemini-embedding-001"]
        for model_name in embed_models:
            print(f"📡 Testing Embedding ({model_name})...")
            try:
                embed_response = client.models.embed_content(
                    model=model_name,
                    contents="This is a test fragment for the A.I.M. forensic archive."
                )
                print(f"✅ Embedding Successful with {model_name} (Size: {len(embed_response.embeddings[0].values)}).")
                break
            except Exception as e:
                print(f"❌ Embedding with {model_name} failed: {str(e)}")

        # 2. Test Generation
        # Trying different models to see which one has a non-zero quota
        gen_models = ["models/gemini-2.0-flash-lite", "models/gemini-1.5-flash", "models/gemini-flash-latest"]
        for gen_model in gen_models:
            print(f"📡 Testing Generation ({gen_model})...")
            try:
                gen_response = client.models.generate_content(
                    model=gen_model,
                    contents="Write a 1-sentence confirmation that the A.I.M. system is online."
                )
                if gen_response and gen_response.text:
                    print(f"✅ Generation Successful with {gen_model}: \"{gen_response.text.strip()}\"")
                    break
                else:
                    print(f"❌ Generation with {gen_model} returned empty text.")
            except Exception as e:
                print(f"❌ Generation with {gen_model} failed: {str(e)}")
                if "429" in str(e):
                    print("   (Quota issue, waiting 5s before next attempt...)")
                    time.sleep(5)

    except Exception as e:
        print(f"❌ API Error: {str(e)}")

if __name__ == "__main__":
    test_api()

